if (e) {
  e.data = e.data || {};
  const now = new Date();

  if (!e.data.pouring_datetime) e.data.pouring_datetime = now.toISOString();

  const h = now.getHours();
  let shift = 'A';
  if (h >= 14 && h < 22) shift = 'B';
  else if (h >= 22 || h < 6) shift = 'C';

  if (!e.data.shift) e.data.shift = shift;
  if (!e.data.operator) e.data.operator = 'Logged In User';
}

set_shift.body:
function getShift(timeString) {
    // Extract hours from time string (e.g., '22:00:00' -> 22)
    const hours = parseInt(timeString.split(':')[0], 10);

    if (hours >= 6 && hours < 14) {
        return 'A'; // Shift A: 06:00 - 14:00
    } else if (hours >= 14 && hours < 22) {
        return 'B'; // Shift B: 14:00 - 22:00
    } else {
        return 'C'; // Shift C: 22:00 - 06:00
    }
}

const targetKey = `${args.field_data_key}`;
const time = e.args[0]; // e.g., '22:00:00'
const shift = getShift(time);

e.data[targetKey] = shift;

// Set pouring_time in meta
e.data.meta = e.data.meta || {};
e.data.meta.pouring_time = time;

