on_time_mount.body:
function getShift(timeString) {
        // Extract hours from time string (e.g., '22:00:00' -> 22)
        const hours = parseInt(timeString.split(':')[0], 10);

        if (hours >= 6 && hours < 14) {
            return 'A'; // Shift A: 06:00 - 14:00
        } else if (hours >= 14 && hours < 22) {
            return 'B'; // Shift B: 14:00 - 22:00
        } else {
            return 'C'; // Shift C: 22:00 - 06:00
        }
    }

    function formatTime(d) {
        return `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}:${String(d.getSeconds()).padStart(2,'0')}`;
    }

    // Ensure time exists — store as "HH:MM:SS" string
    if (!e.data?.time) {
        e.data.time = formatTime(new Date());
    }

    // Ensure meta exists
    e.data.meta = e.data.meta || {};

    // Ensure pouring_time exists — derive from e.data.time
    if (!e.data.meta.pouring_time) {
        const t = e.data.time;
        e.data.meta.pouring_time = typeof t === 'string' ? t : formatTime(new Date(t));
    }

    // Ensure shift exists — derive from time
    if (!e.data?.shift) {
        const time = typeof e.data.time === 'string' ? e.data.time : formatTime(new Date(e.data.time));
        e.data.shift = getShift(time);
    }

on_date_mount.body:
// Ensure date exists
if (!e.data?.date) {
    e.data.date = new Date();
}

// Ensure meta exists
e.data.meta = e.data.meta || {};

// Ensure pouring_date exists — derive from e.data.date
if (!e.data.meta.pouring_date) {
    const d = e.data.date instanceof Date ? e.data.date : new Date(e.data.date);

    if (!isNaN(d)) {
        e.data.meta.pouring_date = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
    }
}

load_grade.body:
const [searchValue, loadCallback, currentDataLength] = e.args;

  console.log(e.args);

  // ✅ Clear previous debounce timer
  if (window._gradesDropdownDebounceTimer) {
      clearTimeout(window._gradesDropdownDebounceTimer);
  }

  // ✅ Abort previous pending request
  if (window._gradesDropdownAbortController) {
      window._gradesDropdownAbortController.abort();
  }

  // ✅ Create new abort controller for this request
  window._gradesDropdownAbortController = new AbortController();
  const signal = window._gradesDropdownAbortController.signal;

  // ✅ Debounce: Wait 300ms before making API call
  window._gradesDropdownDebounceTimer = setTimeout(async () => {

      // ✅ Auth Token from localStorage
      let savedToken = localStorage.getItem('tokenv2');

      // Build URL with query parameters
      let apiUrl = 'https://api.nowpurchase.com/api/c/grades_v2/?page_size=500';

      // Add search parameter if searchValue exists
      if (searchValue) {
          apiUrl += `&search=${encodeURIComponent(searchValue)}`;
      }

      try {
          const res = await fetch(apiUrl, {
              method: 'GET',
              headers: {
                  'authorization': `Token ${savedToken}`
              },
              signal: signal
          });

          const response = await res.json();

          // ✅ Parse results array from response
          const items = Array.isArray(response.results) ? response.results : [];

          // Filter items based on search value (client-side filtering as backup)
          const filteredItems = items.filter(item => {
              const name = item.name || "";
              return name.toLowerCase().includes((searchValue || "").toLowerCase());
          });

          // Create unique map to remove duplicates
          const uniqueMap = new Map();
          filteredItems.forEach(item => {
              const itemName = item.name || "Unnamed Grade";
              const itemId = item.id;

              if (!uniqueMap.has(itemName)) {
                  uniqueMap.set(itemName, {
                      value: itemName,
                      label: itemName,
                      data: {
                          id: item.id,
                          name: item.name,
                          grade_tag_id: item.grade_tag_id,
                          category_name: item.category_name,
                          grade_code: item.grade_code,
                          part_name: item.part_name,
                          part_no: item.part_no,
                          furnace_type: item.furnace_type,
                          item_count: item.item_count,
                          grade_tc: item.grade_tc || [],
                          _raw: item
                      }
                  });
              }
          });

          // Convert map to array and apply pagination
          const preparedData = [...uniqueMap.values()]
              .slice(currentDataLength || 0, (currentDataLength || 0) + 20);

          // ✅ DEBUG: Check what's being sent
          console.log("Final preparedData:", preparedData);

          // SAFETY CHECK
          if (typeof loadCallback === 'function') {
              loadCallback(preparedData);
          } else {
              console.warn("loadCallback is not a function. Check e.args structure:", e.args);
          }

      } catch (err) {
          if (err.name === 'AbortError') {
              console.log('Previous request cancelled');
              return;
          }
          console.error("Dropdown fetch error:", err);
          if (typeof loadCallback === 'function') loadCallback([]);
      }

  }, 300);

